import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"荧光（训练）","description":"","frontmatter":{},"headers":[],"relativePath":"7.UA/2.训练及血统/荧光（训练）.md","filePath":"7.UA/2.训练及血统/荧光（训练）.md"}'),o={name:"7.UA/2.训练及血统/荧光（训练）.md"};function p(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"荧光-训练",tabindex:"-1"},[n("荧光（训练） "),r("a",{class:"header-anchor",href:"#荧光-训练","aria-label":'Permalink to "荧光（训练）"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序001")])])],-1),s('<h1 id="荧光-训练-1" tabindex="-1">荧光（训练） <a class="header-anchor" href="#荧光-训练-1" aria-label="Permalink to &quot;荧光（训练）&quot;">​</a></h1><p>荧光（训练）<br> 前提：决心5<br> 介绍：在走向科技的世界中，原始的人类通过智慧学习并使用石器，而在走向魔法的世界中，原始的人类逐步理解，并学会使用意志来创造奇迹，这便是魔法的起源，而这些人，则被称为荧光。</p><p>D级：<br> 决定目标，纵使前路坎坷，便不再迷惘。这略微坚定的意志也许不会带来巨大的改变，但却是一切的基础。<br> 特性：残烛、坎坷（双特性）<br> 残烛：如同风中的残烛，却未能消亡。意志便是支撑你的一切，你无需饮食、无需休息、也无需呼吸。<br> 坎坷：你的意志上限额外提高等同于决心上的附加成功的数值</p><p>C级：<br> 事物不会按照自己的意愿运行，任何人都会遭遇些许挫折，这对于坚定的信念只是一场磨炼，而经历磨炼的信念，便如同黑夜之中，一点点的微光。<br> 特性：微光，前行、从容、执念（三选一）<br> 微光：你的决心相关检定获得决心上附加成功数*2的内在加值。<br> 购买时选择以下三种能力之一获取，除非重新购买否则不可更换：<br> 前行：你的意志促使你继续前行，获得2AP<br> 从容：你的意志让你从容面对磨难，获得1点全伤害吸收，并获得2点天生防御<br> 执念：你的意志让你在苦难中恢复，使用一个移动动作，立刻恢复2点生命（医疗点数24）</p><p>B级：<br> 经历了些许挫折，心中的火花永不熄灭<br> 特性：火花（双特性），眷顾<br> 火花：你的决心相关检定再获得等同于决心属性的内在加值，此外，每当你经历一个影片，这个加值提升1<br> 眷顾：意志会引发奇迹，虽然，可能只是神明偶尔的怜悯。每轮一次，你的一次决心相关检定可以重掷一次，取其中较高的一次进行结算。</p><p>A级：<br> 或许是家乡的覆灭、或许是挚爱的离开，在经历了重大的变故后，不屈的意志再次升华。<br> 特性：灯（双特性），不要停下来、我思故我在、无所畏惧（三选一，双特性）<br> 灯：那坚定的意志，如同黑夜之下的明灯。你的决心相关检定再获得等同于决心属性的内在加值，你的意志池上限增加等同于你决心属性的数值<br> 购买时选择以下三种能力之一获取，除非重新购买否则不可更换：<br> 不要停下来：信念让你不停前行，击败阻挡你的敌人。额外获得一个标准动作。此外，一回合一次，使用一个自由动作，在本回合获得20高速或者20破甲。<br> 我思故我在：如果意志足够强大，如果你的行动以意志为主体，即使肉体死亡，也许仍能生存吧。在你死亡后，将以灵体的形式存在，以意志力作为结构值，以该形式生存7天后复活。此外，你免疫S级及以下的即死与石化效果。<br> 无所畏惧：纵使从枪林弹雨中走出，也毫发无损，只因我无所畏惧。获得26点天生防御，意志豁免获得22点加值。</p><p>S级：<br> 意志了影响现世，或是创造了名为魔法的事物，亦或是获得了其他的力量，总之，一切魔幻的起源，至此诞生。<br> 特性：原始魔幻（双特性），绝对意志，攻、守（二选一，双特性）<br> 原始魔幻：强大的意志本身创造了魔幻本身。决心相关检定获得等同于决心属性的附加成功，你免疫精神伤害。<br> 绝对意志：你的专注技能相关检定全骰取10，无加值<br> 购买时选择以下两种能力之一获取，除非重新购买否则不可更换：<br> 攻：你的意志倾向于摧毁阻挡你的障碍，你的攻击改为造成韧性伤害，并获得40高速或40破甲<br> 守：你的意志倾向于维持自身的存在，每轮免疫【一次】伤害</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
